INSERT INTO tests (id, name,description) VALUES (1, 'MMPI Мужской', 'MMPI (Миннесотский многопрофильный опросник личности) — это клинически валидизированный инструмент для комплексной оценки личности, разработанный в Университете Миннесоты. Тест выявляет широкий спектр психологических особенностей: от личностных черт и эмоциональных состояний до адаптационных механизмов и возможных психопатологических тенденций. Его методология основана на строгой статистической стандартизации и применяется в диагностической практике, экспертизе и исследованиях.');
INSERT INTO tests (id, name,description) VALUES (2, 'MMPI Женский', 'MMPI (Миннесотский многопрофильный опросник личности) — это клинически валидизированный инструмент для комплексной оценки личности, разработанный в Университете Миннесоты. Тест выявляет широкий спектр психологических особенностей: от личностных черт и эмоциональных состояний до адаптационных механизмов и возможных психопатологических тенденций. Его методология основана на строгой статистической стандартизации и применяется в диагностической практике, экспертизе и исследованиях.');
